import React, {useLayoutEffect, useRef, useState} from 'react'
import classNames from 'classnames'

type CustomCSSProps = React.CSSProperties & {[key: string]: string}

type Props = {
  maxSquareCount?: number
  squareSize?: number
  gutter?: number
}

function calcGridSize(squareCount: number, squareSize: number, gutter: number): number {
  return squareCount * (squareSize + gutter) - gutter
}

export const SquareGrid = ({maxSquareCount = 23, squareSize = 16, gutter = 2}: Props) => {
  const containerRef = useRef<HTMLDivElement | null>(null)
  const [width, setWidth] = useState<number | null>(null)
  const [isRevealed, setIsRevealed] = useState(false)

  // Measure once on mount. We deliberately don't observe resizes: the reserved
  // square box below (aspectRatio + maxWidth) keeps the layout stable, and the
  // grid is a fixed decorative element that doesn't need to reflow live on
  // window resize/rotate. Keep it simple unless that requirement changes.
  useLayoutEffect(() => {
    if (containerRef.current) {
      setWidth(containerRef.current.offsetWidth || containerRef.current.offsetHeight)
    }
  }, [])

  // Reserve the grid's space up-front so filling it after hydration doesn't push
  // siblings down (that was a ~620px layout shift on mobile). The grid is always
  // a square capped at maxSquareCount and always renders ≤ its container width,
  // so a square box of that max size — applied to BOTH the empty placeholder and
  // the filled wrapper — keeps the box height identical across hydration.
  const maxSize = calcGridSize(maxSquareCount, squareSize, gutter)
  const reserveStyle: React.CSSProperties = {maxWidth: maxSize, aspectRatio: '1 / 1'}

  if (!width || !containerRef.current) {
    return <div className="w-full" ref={containerRef} style={reserveStyle}></div>
  }

  const possibleSquareCount = Math.floor((width + gutter) / (squareSize + gutter))
  const squareCount = Math.min(possibleSquareCount, maxSquareCount)

  const bgImageSize = calcGridSize(squareCount, squareSize, gutter)

  const squares = Array.from({length: squareCount * squareCount}, (_, k) => {
    const i = Math.floor(k / squareCount)
    const j = k % squareCount
    return (
      <div
        key={`${i}-${j}`}
        className="square-grid-item"
        style={
          {
            '--animation-order': `${j + i}`,
            'backgroundPosition': `-${j * (squareSize + gutter)}px -${i * (squareSize + gutter)}px`,
          } as CustomCSSProps
        }
      ></div>
    )
  })

  return (
    <div className="w-full flex lg:justify-end" ref={containerRef} style={reserveStyle}>
      <div
        className={classNames('square-grid-container', {isRevealed, 'cursor-pointer': !isRevealed})}
        onClick={() => setIsRevealed(true)}
        style={
          {
            '--square-count': `${squareCount}`,
            '--square-size': `${squareSize}px`,
            '--gutter': `${gutter}px`,
            '--bg-image-size': `${bgImageSize}px`,
          } as CustomCSSProps
        }
      >
        {squares}
      </div>
    </div>
  )
}
